// 功能：提取二进制图片转Base64 + 透传原始文字信息
// ================================================

// 1. 获取当前项的原始 JSON 数据（透传上游文字信息）
// $input.item.json 包含了上游节点传来的所有文本/结构化数据
const originalJson = $input.item.json;

// 2. 获取所有输入项并提取 Base64 列表
const items = $input.all();
const base64_list = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];

  if (item.binary) {
    // 遍历当前项中的所有二进制字段（如 ckimage0, ckimage1 等）
    for (const key of Object.keys(item.binary)) {
      try {
        // 【核心修改】使用官方 helper 方案读取 Buffer
        const buffer = await this.helpers.getBinaryDataBuffer(i, key);

        // 将 Buffer 转换为纯净的 Base64 字符串
        const cleanBase64 = buffer.toString('base64');

        base64_list.push({
          mime_type: item.binary[key].mimeType || 'image/png',
          data: cleanBase64
        });
      } catch (error) {
        console.error(`读取二进制字段 ${key} 失败:`, error);
      }
    }
  }
}

// 3. 返回合并后的数据
// json 对象中既包含 base64_list，也包含原始的 inputData
return [{
  json: {
    base64_list: base64_list,
    total_images: base64_list.length,
    // 透传上游的文字信息
    inputData: originalJson 
  }
}];

