// n8n Code 节点专用代码
// 功能：主动获取 Edit Fields 节点的输出数据，并提取其中所有以 'ckimage' 和 'cpimage' 开头的 binary 图片
// 返回：包含 Edit Fields 节点的 JSON 数据和提取出的图片的数据结构
// ================================================

const processInputAndImages = () => {
  try {
    // 1. 主动获取 Edit Fields 节点的输出数据
    let editFieldsData = {};
    let editFieldsBinary = {};
    let extractedImages = {};
    let extractedImageCount = 0;

    try {
      const editFieldsItems = $('Edit Fields').all();

      if (editFieldsItems && editFieldsItems.length > 0) {
        // 假设我们处理第一个 item
        const firstItem = editFieldsItems[0];
        editFieldsData = firstItem.json || {};
        editFieldsBinary = firstItem.binary || {};

        // 2. 从 Edit Fields 的 binary 数据中提取所有以 'ckimage' 和 'cpimage' 开头的图片
        Object.keys(editFieldsBinary).forEach(key => {
          // 修改点：同时检查 'ckimage' 和 'cpimage' 前缀
          if (key.startsWith('cpimage') || key.startsWith('cpimage')) {
            // 重命名：保持原名或改成 ckimage_0, ckimage_1 等（这里保留原名，避免冲突）
            extractedImages[key] = { ...editFieldsBinary[key] };  // 深拷贝 binary 对象
            extractedImageCount++;
          }
        });
      }
    } catch (editFieldsErr) {
      console.log('获取 Edit Fields 节点失败:', editFieldsErr.message);
      return [{
        json: {
          error: '获取 Edit Fields 节点失败',
          errorDetail: editFieldsErr.message
        }
      }];
    }

    // 调试日志
    console.log('Edit Fields binary 总键数:', Object.keys(editFieldsBinary).length);
    console.log('从 Edit Fields 提取到的图片数:', extractedImageCount);
    console.log('提取到的图片键名列表:', Object.keys(extractedImages));

    // 3. 返回结果
    return [{
      json: {
        // Edit Fields 节点的原始 JSON 数据
        editFieldsData: editFieldsData,

        // 提取出的图片元数据
        extractedImages: extractedImages,
        extractedImageCount: extractedImageCount,
        extractedImageKeys: Object.keys(extractedImages),

        // 源信息
        source: 'extracted_ckimage_cpimage_from_Edit_Fields'
      },

      // 包含所有从 Edit Fields 提取出的图片的 binary 数据
      binary: extractedImages
    }];

  } catch (err) {
    console.log('执行失败:', err.message);
    return [{
      json: {
        error: '执行失败',
        errorDetail: err.message
      }
    }];
  }
};

// 执行并返回
return processInputAndImages();

