// ================================================
// n8n Code 节点 - 提取描述和合并图像
// 保留尺寸信息: "第 1 张图片（1200X600）：描述..."
// ================================================

let text = '';
const descriptions = {};
const images = {};
let index = 0;

// 1. 提取所有输入项的文本和 binary
const allItems = $input.all();

for (let i = 0; i < allItems.length; i++) {
  const item = allItems[i];

  // 提取文本
  if (item.json?.output && typeof item.json.output === 'string') {
    text += item.json.output + '\n';
  }

  // 提取当前 item 的 binary
  if (item.binary) {
    for (const originalKey in item.binary) {
      if (Object.prototype.hasOwnProperty.call(item.binary, originalKey)) {
        const newKey = `${++index}图`;
        images[newKey] = {
          ...item.binary[originalKey],
          sourceNode: 'current_input',
          sourceField: originalKey,
          originalIndex: i
        };
      }
    }
  }
}

// 2. 清洗文本
text = text
  .replace(/^\s*<\|\s*begin_of_box\s*\|>\s*/i, '')
  .replace(/\s*<\|\s*end_of_box\s*\|>\s*$/i, '')
  .trim();

// 3. 解析描述 - 保留尺寸信息
// 格式: "第 1 张图片（1200X600）：描述..."
// 捕获: 序号 + 完整尺寸括号 + 描述内容
const pattern = /第\s*(\d+)\s*张图片([（(][^）)]+[）)])\s*[：:]\s*([\s\S]*?)(?=第\s*\d+\s*张图片|$)/g;

let match;
while ((match = pattern.exec(text)) !== null) {
  const num = match[1];        // 序号: "1"
  const size = match[2];      // 尺寸: "（1200X600）"
  let value = match[3].trim().replace(/\n+$/, '');

  if (value) {
    // 将尺寸信息前置到描述中
    const fullDescription = `第 ${num} 张图片${size}：${value}`;
    descriptions[`${num}图`] = fullDescription;
  }
}

// 4. 从 Edit Fields 节点提取 cpimage 开头的 binary
let editFieldsImageCount = 0;
let editFieldsConnected = false;

try {
  let editFieldsNode;
  try { editFieldsNode = $('Edit Fields'); } catch(e) {}
  try { if (!editFieldsNode) editFieldsNode = $('Edit_Fields'); } catch(e) {}
  try { if (!editFieldsNode) editFieldsNode = $('edit-fields'); } catch(e) {}
  try { if (!editFieldsNode) editFieldsNode = $('Edit Fields2'); } catch(e) {}

  const editFieldsOutput = editFieldsNode ? editFieldsNode.all() : [];

  for (const item of editFieldsOutput) {
    if (!item?.binary) continue;

    for (const key in item.binary) {
      if (key.startsWith('cpimage')) {
        const newKey = `${++index}图`;
        images[newKey] = {
          ...item.binary[key],
          sourceNode: 'Edit Fields',
          sourceField: key
        };
        editFieldsImageCount++;
      }
    }
  }

  editFieldsConnected = editFieldsImageCount > 0;
} catch (err) {
  console.error("Edit Fields node error:", err.message);
}

// 5. 验证并输出
const descCount = Object.keys(descriptions).length;
const imgCount = Object.keys(images).length;

// 调试信息
console.log('Descriptions:', descriptions);
console.log('Images keys:', Object.keys(images));

// 6. 返回 n8n 标准格式
return [{
  json: {
    descriptions,
    images: Object.keys(images),
    imageCount: imgCount,
    descriptionCount: descCount,
    inputImageCount: index - editFieldsImageCount,
    editFieldsImageCount,
    editFieldsConnected,
    matchedPairs: Object.keys(descriptions).filter(k => images[k]).length
  },
  binary: images
}];

